#!/usr/bin/env node
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const repoRoot = process.cwd();
const auditPath = path.join(
  repoRoot,
  'apps/mcp-superserver/src/ledger-tool-audit.generated.json'
);
const reportPath = path.join(repoRoot, 'open-source/gnosis/PROOF_ARTIFACT_PATHS.md');

function classifyArtifactPath(proofArtifactPath) {
  if (!proofArtifactPath) return 'empty';
  if (proofArtifactPath === 'open-source/gnosis/THEOREM_LEDGER.md') return 'ledgerFallback';
  if (
    proofArtifactPath.startsWith('open-source/gnosis-math/Gnosis/') &&
    proofArtifactPath.endsWith('.lean')
  ) {
    return 'gnosisMathLean';
  }
  if (
    proofArtifactPath.startsWith('open-source/gnosis/lean/') &&
    proofArtifactPath.endsWith('.lean')
  ) {
    return 'gnosisLegacyLean';
  }
  if (
    proofArtifactPath.startsWith('open-source/gnosis/tla/') &&
    proofArtifactPath.endsWith('.tla')
  ) {
    return 'gnosisTla';
  }
  if (proofArtifactPath.startsWith('open-source/gnosis/')) return 'gnosisOther';
  return 'other';
}

function increment(map, key) {
  map.set(key, (map.get(key) ?? 0) + 1);
}

const audit = JSON.parse(readFileSync(auditPath, 'utf8'));
const entries = Array.isArray(audit.entries) ? audit.entries : [];
const classCounts = new Map();
const missing = [];
const empty = [];

for (const entry of entries) {
  const artifactPath = entry.proofArtifactPath ?? '';
  const classification = classifyArtifactPath(artifactPath);
  increment(classCounts, classification);

  if (!artifactPath) {
    empty.push(entry);
  } else if (!existsSync(path.join(repoRoot, artifactPath))) {
    missing.push(entry);
  }
}

const orderedClasses = [
  ['gnosisMathLean', 'Gnosis Math Lean modules'],
  ['gnosisLegacyLean', 'Gnosis legacy Lean modules'],
  ['gnosisTla', 'Gnosis TLA+ artifacts'],
  ['gnosisOther', 'Gnosis non-Lean artifacts'],
  ['ledgerFallback', 'Ledger fallback rows'],
  ['other', 'Other existing artifacts'],
  ['empty', 'Empty artifact paths'],
];

const lines = [
  '# Proof Artifact Paths',
  '',
  'Parent: [Gnosis](./README.md)',
  '',
  'Generated by `node open-source/gnosis/scripts/audit-ledger-proof-artifact-paths.mjs`.',
  '',
  'This report audits the `proofArtifactPath` values emitted by `apps/mcp-superserver/src/ledger-tool-audit.generated.json` so stale MCP links fail as a visible ledger artifact instead of hiding in generated code.',
  '',
  '## Summary',
  '',
  `- Generated MCP ledger entries: ${entries.length}`,
  `- Missing artifact paths: ${missing.length}`,
  `- Empty artifact paths: ${empty.length}`,
  '',
  '## Artifact Classes',
  '',
  '| Class | Entries |',
  '|---|---:|',
];

for (const [key, label] of orderedClasses) {
  lines.push(`| ${label} | ${classCounts.get(key) ?? 0} |`);
}

lines.push('', '## Missing Artifacts', '', '| Theorem ID | Server | Artifact path |', '|---|---|---|');
for (const entry of missing) {
  lines.push(
    `| \`${entry.toolTheoremId ?? ''}\` | \`${entry.server ?? ''}\` | \`${entry.proofArtifactPath ?? ''}\` |`
  );
}

lines.push('', '## Empty Artifact Paths', '', '| Theorem ID | Server | Tool |', '|---|---|---|');
for (const entry of empty) {
  lines.push(
    `| \`${entry.toolTheoremId ?? ''}\` | \`${entry.server ?? ''}\` | \`${entry.tool ?? ''}\` |`
  );
}

writeFileSync(reportPath, `${lines.join('\n')}\n`, 'utf8');
console.log(`Wrote ${path.relative(repoRoot, reportPath)}`);
console.log(`Missing artifact paths: ${missing.length}`);
console.log(`Empty artifact paths: ${empty.length}`);
